async (params, browser) => {
  // Open Slack
  await browser.open('https://app.slack.com')

  // Let Slack load
  await browser.wait(3000)

  // Search messages via Slack API
  const result = await browser.evaluate(`const localConfig = localStorage.getItem('localConfig_v2'); if (!localConfig) throw new Error('Not logged into Slack'); const config = JSON.parse(localConfig); const teamId = Object.keys(config.teams)[0]; const token = config.teams[teamId].token; const resp = await fetch('/api/search.messages', { method: 'POST', headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/x-www-form-urlencoded' }, body: 'query=' + encodeURIComponent(params.query) + '&count=20' }); const data = await resp.json(); if (!data.ok) throw new Error('Search failed: ' + data.error); const messages = (data.messages?.matches || []).map(m => ({ text: m.text?.substring(0, 200) || '', username: m.username || '', channel: m.channel?.name || '', ts: m.ts, permalink: m.permalink || '' })); return { total: data.messages?.total || 0, result_count: messages.length, messages: messages }`)

  return result
}
